public int lastRemaining(int n) {
    boolean direction = true;
    int head = 1, remaining = n, step = 1;

    while (remaining > 1) {
        if (direction || remaining % 2 == 1) {
            head += step;
        }
        remaining /= 2;
        step *= 2;
        direction = !direction;
    }

    return head;
}
```

